import os

def generate_tree(startpath):
    tree = []
    ignore_dirs = {'.git', 'venv', '__pycache__', '.vscode', 'generated_images', 'data'}
    for root, dirs, files in os.walk(startpath):
        dirs[:] = [d for d in dirs if d not in ignore_dirs]
        level = root.replace(startpath, '').count(os.sep)
        indent = ' ' * 4 * level
        tree.append(f'{indent}{os.path.basename(root)}/')
        subindent = ' ' * 4 * (level + 1)
        for f in files:
            if not f.lower().endswith(('.png', '.jpg', '.jpeg', '.pdf', '.pyc', '.exe', '.zip', '.mp4', '.mov', '.avi')):
                tree.append(f'{subindent}{f}')
    return "\n".join(tree)

def export_project():
    output_file = "codigo_completo_para_gemini.txt"
    ignore_dirs = {'.git', 'venv', '__pycache__', '.vscode', 'generated_images', 'data'}
    ignore_extensions = {'.png', '.jpg', '.jpeg', '.pdf', '.pyc', '.exe', '.zip', '.mp4', '.mov', '.avi', '.docx', '.xlsx', '.pptx'}

    with open(output_file, "w", encoding="utf-8") as out:
        out.write("================================================================\n")
        out.write("ESTRUCTURA DEL PROYECTO\n")
        out.write("================================================================\n\n")
        out.write(generate_tree(os.getcwd()))
        out.write("\n\n")

        for root, dirs, files in os.walk(os.getcwd()):
            # Ignorar directorios prohibidos
            dirs[:] = [d for d in dirs if d not in ignore_dirs]

            for file in files:
                ext = os.path.splitext(file)[1].lower()
                if ext in ignore_extensions:
                    continue
                if file == ".env" or file == output_file or file == "export_project.py":
                    continue

                filepath = os.path.join(root, file)
                rel_path = os.path.relpath(filepath, os.getcwd())

                out.write("================================================================\n")
                out.write(f"ARCHIVO: {rel_path}\n")
                out.write("================================================================\n")
                try:
                    with open(filepath, "r", encoding="utf-8") as f:
                        out.write(f.read())
                except Exception as e:
                    out.write(f"Error al leer archivo: {e}")
                out.write("\n\n")

    print(f"✅ Proyecto exportado con éxito a: {output_file}")

if __name__ == "__main__":
    export_project()

def parse_intent(prompt: str) -> tuple[bool, str]:
    """
    Analiza el prompt del usuario y devuelve si es un comando de imagen
    y el prompt artístico extraído.
    Retorna: (es_comando_imagen, prompt_artistico)
    """
    prompt_lower = prompt.strip().lower()
    triggers_arte = [
        "crea una imagen", "genera una imagen", "crear una imagen", 
        "generar una imagen", "dibuja una imagen", "haz una imagen"
    ]

    for trigger in triggers_arte:
        if trigger in prompt_lower:
            return True, prompt.strip()

    return False, ""

import os
import subprocess
from PIL import Image
import pypandoc

def get_file_type(filepath: str) -> str:
    ext = os.path.splitext(filepath)[1].lower()
    if ext in ['.png', '.jpg', '.jpeg', '.webp', '.bmp', '.gif', '.tiff', '.ico']:
        return 'image'
    elif ext in ['.mp4', '.avi', '.mkv', '.mov', '.webm', '.mp3', '.wav', '.ogg', '.flac', '.aac']:
        return 'media'
    elif ext in ['.docx', '.md', '.rst', '.html', '.epub', '.odt', '.pdf']:
        return 'document'
    return 'unknown'

def convert_image(input_path: str, output_path: str) -> bool:
    try:
        with Image.open(input_path) as img:
            # Handle RGBA to RGB if converting to JPEG
            if output_path.lower().endswith(('.jpg', '.jpeg')) and img.mode in ('RGBA', 'P'):
                img = img.convert('RGB')
            img.save(output_path)
        return True
    except Exception as e:
        print(f"Error converting image: {e}")
        return False

def convert_media(input_path: str, output_path: str) -> bool:
    try:
        # Calls local ffmpeg directly. Relies on FFmpeg being in PATH.
        command = [
            "ffmpeg", "-y", "-i", input_path, output_path
        ]
        result = subprocess.run(command, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
        if result.returncode != 0:
            print(f"FFmpeg Error: {result.stderr}")
            return False
        return True
    except Exception as e:
        print(f"Error converting media: {e}")
        return False

def convert_document(input_path: str, output_path: str) -> bool:
    try:
        in_ext = os.path.splitext(input_path)[1].lower()
        out_ext = os.path.splitext(output_path)[1].lower()

        if in_ext == '.pdf' and out_ext == '.docx':
            from pdf2docx import parse
            parse(input_path, output_path)
            return True

        # pandoc input -o output
        pypandoc.convert_file(input_path, to=out_ext.replace('.', ''), outputfile=output_path)
        return True
    except Exception as e:
        print(f"Error converting document: {e}")
        return False

def run_conversion(input_path: str, output_path: str) -> bool:
    file_type = get_file_type(input_path)

    if file_type == 'image':
        return convert_image(input_path, output_path)
    elif file_type == 'media':
        return convert_media(input_path, output_path)
    elif file_type == 'document':
        return convert_document(input_path, output_path)
    else:
        # Fallback to FFmpeg which handles a lot of weird things just in case
        return convert_media(input_path, output_path)

""" document_parser.py — Router Universal de Archivos ================================================== Extrae contenido legible de CUALQUIER archivo para enviarlo al LLM.
Arquitectura (Strategy Pattern): 1. Si la extensión tiene un extractor dedicado → úsalo. 2. Si no → intenta lectura como texto plano (UTF-8, con fallback a latin-1). 3. Si el archivo es binario ininteligible → devuelve un mensaje de error manejado, nunca lanza una excepción sin atrapar.
Regla de Chesterton's Fence: Se conservan TODOS los parsers anteriores (_parse_pdf, _parse_docx, etc.) ya que son consumidos activamente por el flujo de chat existente. Solo se expande el comportamiento de `extraer_texto_archivo` hacia abajo. """
import os import io import base64 from pathlib import Path
import pandas as pd from pypdf import PdfReader from docx import Document from pptx import Presentation from odf.opendocument import load as odf_load from odf.teletype import extractText as odf_extract_text
# ─── Extensiones clasificadas como imágenes ──────────────────────────────────── _IMAGEN_EXTENSIONS = {'.png', '.jpg', '.jpeg', '.webp', '.gif', '.bmp', '.tiff', '.tif', '.ico', '.svg'}
# ─── Extensiones clasificadas como vídeo (pasan por ruta de Gemini) ──────────── _VIDEO_EXTENSIONS = {'.mp4', '.mov', '.avi', '.mkv', '.webm', '.flv', '.wmv'}
# ─── Binarios conocidos que NUNCA tienen texto legible ───────────────────────── _BINARY_EXTENSIONS = { '.exe', '.dll', '.so', '.dylib', '.bin', '.dat', '.db', '.sqlite', '.zip', '.tar', '.gz', '.rar', '.7z', '.bz2', '.pyc', '.pyo', '.class', '.jar', '.war', '.mp3', '.wav', '.ogg', '.flac', '.m4a', '.aac', '.ttf', '.otf', '.woff', '.woff2', }
# ─── Parsers dedicados (Patrón Strategy) ──────────────────────────────────────
def _parse_pdf(file_obj) -> str: reader = PdfReader(file_obj) paginas = [page.extract_text() for page in reader.pages if page.extract_text()] if not paginas: return "⚠️ El PDF no contiene texto extraíble (puede ser un PDF escaneado sin OCR)." return "\n".join(paginas)
def _parse_docx(file_obj) -> str: doc = Document(file_obj) return "\n".join([para.text for para in doc.paragraphs if para.text.strip()])
def _parse_odf(file_obj) -> str: doc = odf_load(file_obj) return odf_extract_text(doc)
def _parse_excel(file_obj, is_ods: bool = False) -> str: motor = 'odf' if is_ods else None df = pd.read_excel(file_obj, engine=motor) return f"Datos de la hoja de cálculo:\n{df.to_string()}"
def _parse_csv(file_obj) -> str: # Intentar con UTF-8 primero, fallback a latin-1 try: df = pd.read_csv(file_obj) except UnicodeDecodeError: file_obj.seek(0) df = pd.read_csv(file_obj, encoding='latin-1') return f"Datos del CSV:\n{df.to_string()}"
def _parse_pptx(file_obj) -> str: prs = Presentation(file_obj) texto = [] for slide in prs.slides: for shape in slide.shapes: if hasattr(shape, "text") and shape.text.strip(): texto.append(shape.text) return "\n".join(texto)
def _parse_text(file_obj) -> str: """Lee cualquier archivo de texto. Intenta UTF-8, luego latin-1.""" raw = file_obj.read() try: return raw.decode("utf-8") except UnicodeDecodeError: return raw.decode("latin-1", errors="replace")
def _parse_json(file_obj) -> str: import json try: data = json.load(file_obj) return f"Contenido JSON:\n{json.dumps(data, indent=2, ensure_ascii=False)}" except json.JSONDecodeError as e: file_obj.seek(0) return f"JSON malformado (mostrando texto plano):\n{_parse_text(file_obj)}\n\nError de parseo: {e}"
def _parse_image_as_description(file_obj) -> str: """ Para imágenes: devuelve metadata básica + Base64 del contenido. El LLM de visión (Gemini) ya tiene su propia ruta en app.py para procesar imágenes como objeto PIL. Este parser solo actúa como fallback de contexto. """ raw = file_obj.read() nombre = getattr(file_obj, 'name', 'imagen') ext = Path(nombre).suffix.lower().lstrip('.') b64 = base64.b64encode(raw).decode('utf-8') size_kb = len(raw) / 1024 return ( f"[Imagen adjunta: {nombre} | Tamaño: {size_kb:.1f} KB | Formato: {ext.upper()}]\n" f"data:image/{ext};base64,{b64[:200]}... (contenido Base64 truncado para contexto)" )
# ─── Mapa de estrategias (extensión → parser) ───────────────────────────────── _EXTRACTORS: dict = { # Documentos ricos '.pdf': _parse_pdf, '.docx': _parse_docx, '.odt': _parse_odf, '.odp': _parse_odf, '.pptx': _parse_pptx, # Hojas de cálculo '.xlsx': _parse_excel, '.xls': _parse_excel, '.ods': lambda f: _parse_excel(f, is_ods=True), '.csv': _parse_csv, # Texto y código (todos pasan por _parse_text) '.txt': _parse_text, '.md': _parse_text, '.py': _parse_text, '.js': _parse_text, '.ts': _parse_text, '.jsx': _parse_text, '.tsx': _parse_text, '.html': _parse_text, '.htm': _parse_text, '.css': _parse_text, '.scss': _parse_text, '.xml': _parse_text, '.yaml': _parse_text, '.yml': _parse_text, '.toml': _parse_text, '.ini': _parse_text, '.env': _parse_text, '.sh': _parse_text, '.bat': _parse_text, '.sql': _parse_text, '.rs': _parse_text, '.go': _parse_text, '.java': _parse_text, '.cpp': _parse_text, '.c': _parse_text, '.h': _parse_text, '.php': _parse_text, '.rb': _parse_text, '.kt': _parse_text, '.swift': _parse_text, '.r': _parse_text, '.log': _parse_text, '.conf': _parse_text, '.cfg': _parse_text, # JSON (parser dedicado con pretty-print) '.json': _parse_json, '.jsonl': _parse_text, # Imágenes (fallback informativo — la ruta Gemini Vision es la principal) **{ext: _parse_image_as_description for ext in _IMAGEN_EXTENSIONS}, }
# ─── Fallback Universal ────────────────────────────────────────────────────────
def _fallback_universal(file_obj, nombre: str) -> str: """ Último recurso para archivos sin extractor dedicado. Intenta leer como texto UTF-8 → latin-1. Si es binario ininteligible, devuelve un mensaje de error manejado. """ ext = Path(nombre).suffix.lower()
# Cortocircuito rápido para binarios conocidos if ext in _BINARY_EXTENSIONS: return ( f"⛔ No se pudo extraer texto legible de '{nombre}'.\n" f"Motivo: El formato '{ext}' es un archivo binario sin representación textual.\n" f"Sugerencia: Si necesitas analizar su contenido, conviértelo primero " f"usando el 'Estudio de Conversión' del panel lateral." )
# Intentar lectura de texto para extensiones desconocidas try: raw = file_obj.read() # Heurística: si más del 30% de los primeros 512 bytes son nulos o no imprimibles → binario muestra = raw[:512] bytes_no_imprimibles = sum(1 for b in muestra if b < 9 or (14 <= b <= 31) or b == 127) if len(muestra) > 0 and (bytes_no_imprimibles / len(muestra)) > 0.30: return ( f"⛔ No se pudo extraer texto legible de '{nombre}'.\n" f"Motivo: El archivo parece ser un binario (alta proporción de bytes no imprimibles).\n" f"Extensión detectada: '{ext or 'sin extensión'}'" ) # Es texto — decodificar try: return raw.decode("utf-8") except UnicodeDecodeError: return raw.decode("latin-1", errors="replace")
except Exception as e: return f"⛔ Error inesperado al leer '{nombre}': {e}"
# ─── Función Pública Principal ─────────────────────────────────────────────────
def extraer_texto_archivo(file_obj) -> str: """ Router Universal de Archivos.
Recibe cualquier objeto de archivo (Streamlit UploadedFile o file-like) y devuelve SIEMPRE un string con el contenido legible o un mensaje de error descriptivo. NUNCA devuelve None.
Flujo de decisión: 1. Extractor dedicado por extensión → usa el parser específico. 2. Sin extractor → fallback universal (heurística de texto/binario). 3. Cualquier excepción interna → capturada y convertida a mensaje de error. """ nombre = getattr(file_obj, 'name', 'archivo_sin_nombre') ext = Path(nombre.lower()).suffix
# Early return: extensiones de vídeo — se procesan por ruta separada en app.py if ext in _VIDEO_EXTENSIONS: return f"[Archivo de vídeo detectado: {nombre} — procesado por ruta de análisis de vídeo]"
extractor = _EXTRACTORS.get(ext)
if extractor: try: return extractor(file_obj) except Exception as e: return ( f"⚠️ Error procesando '{nombre}' con el parser de '{ext}':\n{e}\n\n" f"Intentando lectura como texto plano..." f"\n{_fallback_universal(file_obj, nombre)}" )
# Sin extractor dedicado → Fallback Universal return _fallback_universal(file_obj, nombre)

import os
import json
import requests
import datetime
import google.genai as ggenai 
from google.genai import types
from groq import Groq

from src.core.config import (
    CLAVE_GEMINI, CLAVE_GROQ, CLAVE_OPENROUTER, CLAVE_OPENAI,
    CARPETA_IMAGENES, PROMPT_TECH_LEAD
)
from openai import OpenAI

class LLMProvider:
    """Clase base (Wrapper) para proveedores de modelos de lenguaje."""
    def stream_chat(self, mensaje: str, historial: list, system_instruction: str = None):
        raise NotImplementedError

class GeminiProvider(LLMProvider):
    def stream_chat(self, carga_util, historial=None, system_instruction: str = None):
        try:
            cliente = ggenai.Client(api_key=CLAVE_GEMINI)
            model_name = 'gemini-2.5-pro'

            # Configuramos los filtros de seguridad al mínimo para evitar que corte el código fuente generado
            safety_settings = [
                types.SafetySetting(
                    category=types.HarmCategory.HARM_CATEGORY_HATE_SPEECH,
                    threshold=types.HarmBlockThreshold.BLOCK_NONE,
                ),
                types.SafetySetting(
                    category=types.HarmCategory.HARM_CATEGORY_HARASSMENT,
                    threshold=types.HarmBlockThreshold.BLOCK_NONE,
                ),
                types.SafetySetting(
                    category=types.HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT,
                    threshold=types.HarmBlockThreshold.BLOCK_NONE,
                ),
                types.SafetySetting(
                    category=types.HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT,
                    threshold=types.HarmBlockThreshold.BLOCK_NONE,
                ),
            ]

            config = types.GenerateContentConfig(
                system_instruction=system_instruction or PROMPT_TECH_LEAD, 
                temperature=0.2, # Reducido a 0.2 para código más preciso y menos propenso a errores de formato
                max_output_tokens=8192,
                safety_settings=safety_settings
            )

            chat = cliente.chats.create(model=model_name, config=config)
            for frag in chat.send_message_stream(carga_util):
                # Gemini Vision puede emitir fragmentos con text=None durante el procesamiento
                if frag.text is not None:
                    yield frag.text
        except Exception as e: 
            yield f"\n\n❌ Error Gemini Texto: {e}"

    def generar_imagen(self, prompt_artistico: str):
        try:
            if not CLAVE_GEMINI: return None, "❌ Falta Gemini API Key."

            cliente = ggenai.Client(api_key=CLAVE_GEMINI)

            resultado = cliente.models.generate_images(
                model='imagen-4.0-generate-001',
                prompt=prompt_artistico,
                config=types.GenerateImagesConfig(
                    number_of_images=1,
                    output_mime_type="image/png",
                    aspect_ratio="1:1"
                )
            )

            if resultado.generated_images:
                image_bytes = resultado.generated_images[0].image.image_bytes

                timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
                filename = f"gen_{timestamp}.png"
                final_path = os.path.join(CARPETA_IMAGENES, filename)

                with open(final_path, "wb") as f:
                    f.write(image_bytes)

                return final_path, None 
            else:
                return None, "⚠️ La IA no devolvió una imagen."

        except Exception as e:
            return None, f"❌ Error crítico en Generador de Arte: {e}"

class GroqProvider(LLMProvider):
    def __init__(self, model="llama-3.3-70b-versatile"):
        self.model = model

    def stream_chat(self, mensaje: str, historial: list, system_instruction: str = None):
        try:
            cliente = Groq(api_key=CLAVE_GROQ)
            mensajes = [{"role": "system", "content": system_instruction or PROMPT_TECH_LEAD}]
            for m in historial: 
                if m.get("content"):
                    mensajes.append({"role": m["role"], "content": m["content"]})
            mensajes.append({"role": "user", "content": mensaje})
            stream = cliente.chat.completions.create(
                model=self.model, 
                messages=mensajes, 
                stream=True,
                max_tokens=8192,
                temperature=0.2 # Reducido para mayor precisión en código
            )
            for chunk in stream:
                if chunk.choices[0].delta.content: yield chunk.choices[0].delta.content
        except Exception as e: 
            yield f"\n\n❌ Error Groq: {e}"

class OllamaProvider(LLMProvider):
    def stream_chat(self, mensaje: str, historial: list, system_instruction: str = None):
        url = "http://localhost:11434/api/chat"
        mensajes = [{"role": "system", "content": system_instruction or PROMPT_TECH_LEAD}]
        for m in historial:
            if m.get("content"):
                mensajes.append({"role": m["role"], "content": m["content"]})
        mensajes.append({"role": "user", "content": mensaje})
        try:
            res = requests.post(url, json={"model": "qwen2.5-coder:3b", "messages": mensajes, "stream": True}, stream=True)
            for linea in res.iter_lines():
                if linea: yield json.loads(linea)["message"]["content"]
        except Exception as e: 
            yield f"\n\n❌ Error Ollama: {e}"

class OpenRouterProvider(LLMProvider):
    def stream_chat(self, mensaje: str, historial: list, system_instruction: str = None):
        try:
            import os
            from dotenv import load_dotenv
            load_dotenv(override=True)
            clave_actual = os.getenv("OPENROUTER_API_KEY")

            if not clave_actual:
                yield "❌ Error: No se ha encontrado OPENROUTER_API_KEY en el archivo .env"
                return

            cliente = OpenAI(
                api_key=clave_actual,
                base_url="https://openrouter.ai/api/v1",
            )
            mensajes = [{"role": "system", "content": system_instruction or PROMPT_TECH_LEAD}]
            for m in historial: 
                if m.get("content"):
                    mensajes.append({"role": m["role"], "content": m["content"]})
            mensajes.append({"role": "user", "content": mensaje})
            stream = cliente.chat.completions.create(
                model="qwen/qwen3-coder:free",
                messages=mensajes,
                stream=True
            )
            for chunk in stream:
                if chunk.choices[0].delta.content: yield chunk.choices[0].delta.content
        except Exception as e: 
            yield f"\n\n❌ Error OpenRouter: {e}"


class GroqWhisperProvider:
    """
    Wrapper de Groq Whisper para STT (Speech-to-Text).
    Delega completamente en audio_service.transcribe_audio_with_groq.
    Expone un método `transcribe` en lugar de `stream_chat` porque el
    contrato de audio es fundamentalmente diferente al de chat.
    """

    def transcribe(self, audio_bytes: bytes, filename: str = "audio.webm") -> tuple[str, str | None]:
        """
        Transcribe audio a texto.

        Args:
            audio_bytes: Contenido binario del archivo de audio.
            filename: Nombre del archivo para que la API infiera el formato.

        Returns:
            Tuple (texto_transcrito, error_message). error_message es None si éxito.
        """
        from src.services.audio_service import transcribe_audio_with_groq
        return transcribe_audio_with_groq(audio_bytes, filename)


class OpenAITTSProvider:
    """
    Wrapper de OpenAI TTS para síntesis de voz (Text-to-Speech).
    Delega completamente en audio_service.synthesize_speech_with_openai.
    """

    VOCES_DISPONIBLES = ["alloy", "echo", "fable", "onyx", "nova", "shimmer"]

    def __init__(self, voice: str = "alloy"):
        # Validación defensiva: si la voz no es válida, usamos el default
        self.voice = voice if voice in self.VOCES_DISPONIBLES else "alloy"

    def synthesize(self, text: str) -> tuple[bytes | None, str | None, str | None]:
        """
        Sintetiza texto a audio MP3.

        Args:
            text: El texto a convertir en voz (máx. 4096 caracteres).

        Returns:
            Tuple (audio_bytes, saved_filepath, error_message).
            audio_bytes: Bytes del MP3 (para reproducción directa en Streamlit).
            saved_filepath: Ruta del archivo guardado en disco.
            error_message: None si éxito, descripción del error en caso contrario.
        """
        from src.services.audio_service import synthesize_speech_with_openai
        return synthesize_speech_with_openai(text, voice=self.voice)


class EdgeTTSProvider:
    """
    Wrapper de Edge TTS (Microsoft Edge) para síntesis de voz gratuita.
    No requiere API Key.
    """
    def __init__(self, voice: str = "es-ES-AlvaroNeural"):
        self.voice = voice

    def synthesize(self, text: str) -> tuple[bytes | None, str | None, str | None]:
        from src.services.audio_service import synthesize_speech_with_edge
        return synthesize_speech_with_edge(text, voice=self.voice)
